const input = $input.first().json;
if (!input.state) throw new Error('state ist erforderlich (z.B. "pausiert")');

// Znuny TicketSearch: State-Filter als Query-Parameter
const params = new URLSearchParams({
  UserLogin: 'root@localhost',
  Password: 'ZnunyAdmin2026!',
  'States[0]': input.state,
  Limit: String(input.limit || 100)
});

// Optional: Queue-Filter
if (input.queue) params.append('Queues[0]', input.queue);

return [{ json: { state: input.state, query_string: params.toString() } }];

const input = $('📥 Input from Master').first().json;
const r = $input.first().json;

// Znuny liefert: { TicketID: [1, 2, 3] } oder { Error: {...} }
if (r.Error) {
  return [{ json: { ticket_ids: [], count: 0, state: input.state,
    error: `${r.Error.ErrorCode}: ${r.Error.ErrorMessage}` } }];
}

// TicketID kann Array oder einzelner Wert sein
const raw = r.TicketID;
const ticket_ids = Array.isArray(raw) ? raw.map(Number)
  : (raw != null ? [Number(raw)] : []);

return [{ json: { ticket_ids, count: ticket_ids.length, state: input.state, error: null } }];
